@Component
class AuthorizationCodeStore {

    private final Map<String, AuthorizationCodeEntry> store = new ConcurrentHashMap<>();
    private final Clock clock;

    AuthorizationCodeStore(Clock clock) {
        this.clock = clock;
    }

    public String createCode(String clientId, String redirectUri, String subject, String scope) {
        cleanupExpired();
        String code = TokenGenerator.randomUrlSafeToken(32);
        long nowMs = clock.millis();
        long expMs = nowMs + 10 * 60 * 1000L;
        store.put(code, new AuthorizationCodeEntry(clientId, redirectUri, subject, scope, expMs));
        return code;
    }

    public Optional<AuthorizationCodeEntry> consume(String code) {
        cleanupExpired();
        AuthorizationCodeEntry entry = store.remove(code);
        if (entry == null) return Optional.empty();
        if (entry.expiresAtEpochMs() < clock.millis()) return Optional.empty();
        return Optional.of(entry);
    }

    private void cleanupExpired() {
        long now = clock.millis();
        store.entrySet().removeIf(e -> e.getValue().expiresAtEpochMs() < now);
    }

    record AuthorizationCodeEntry(String clientId, String redirectUri, String subject, String scope, long expiresAtEpochMs) {}
}

final class RedirectUriValidator {
    private RedirectUriValidator() {}

    public static boolean isAllowed(String redirectUri, String registeredBaseUrl) {
        if (redirectUri == null || registeredBaseUrl == null) return false;

        URI redir;
        URI base;
        try {
            redir = URI.create(redirectUri);
            base = URI.create(registeredBaseUrl);
        } catch (Exception e) {
            return false;
        }

        if (!isHttpScheme(redir.getScheme()) || !isHttpScheme(base.getScheme())) return false;
        if (redir.getHost() == null || base.getHost() == null) return false;

        String normalizedRedirect = normalizeForStartsWith(redir);
        String normalizedBase = normalizeForStartsWith(base);

        return normalizedRedirect.startsWith(normalizedBase);
    }

    private static boolean isHttpScheme(String s) {
        if (s == null) return false;
        return "https".equalsIgnoreCase(s) || "http".equalsIgnoreCase(s);
    }

    private static String normalizeForStartsWith(URI uri) {
        String scheme = uri.getScheme().toLowerCase();
        String host = uri.getHost().toLowerCase();
        int port = uri.getPort();
        String authority;
        if (port == -1) {
            authority = host;
        } else {
            authority = host + ":" + port;
        }

        String path = uri.getRawPath();
        if (path == null || path.isEmpty()) path = "/";

        StringBuilder sb = new StringBuilder();
        sb.append(scheme).append("://").append(authority);

        if (!path.startsWith("/")) sb.append("/");
        sb.append(path);

        if (!sb.toString().endsWith("/")) sb.append("/");

        return sb.toString();
    }
}

